var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"CCN No. CSM002M000755-09\\n<color=#ffd34c>3급 요인</color> 열람 승인 자료\\n부록: 대상자 관찰","JPN":"CCN No. CSM002M000755-09\\n<color=#ffd34c>3級要因</color> 閲覧承認資料\\n付録: 対象者観察","ENG":"(ENG)CCN No. CSM002M000755-09\\n<color=#ffd34c>3급 요인</color> 열람 승인 자료\\n부록: 대상자 관찰","TWN":"(TWN)CCN No. CSM002M000755-09\\n<color=#ffd34c>3급 요인</color> 열람 승인 자료\\n부록: 대상자 관찰"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"어서 오게. 새로 배치시킨 장비는 어떤가?","JPN":"さあ来なさい。新たに配置させた装備はどうなのか?","ENG":"(ENG)어서 오게. 새로 배치시킨 장비는 어떤가?","TWN":"(TWN)어서 오게. 새로 배치시킨 장비는 어떤가?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"사용하는 입장이 되니 무척 유용하더군요.","JPN":"使う立場になるからすごく有用ですね。","ENG":"(ENG)사용하는 입장이 되니 무척 유용하더군요.","TWN":"(TWN)사용하는 입장이 되니 무척 유용하더군요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"하지만 예전에도 운용되었다고 생각하니 조금 불쾌해졌습니다.","JPN":"しかしこの前にも運用されたと思うから少し不快になりました。","ENG":"(ENG)하지만 예전에도 운용되었다고 생각하니 조금 불쾌해졌습니다.","TWN":"(TWN)하지만 예전에도 운용되었다고 생각하니 조금 불쾌해졌습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"안심하게. 아무리 그래도 내부 감찰에 투입했겠나.","JPN":"安心しなさい。いくらでも内部監察に投入したか。","ENG":"(ENG)안심하게. 아무리 그래도 내부 감찰에 투입했겠나.","TWN":"(TWN)안심하게. 아무리 그래도 내부 감찰에 투입했겠나."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"방금 그 말씀, 가슴에 손을 올리고 다시 해 보시죠.","JPN":"今そのお話、胸に手を上げてまたして布施ですよ。","ENG":"(ENG)방금 그 말씀, 가슴에 손을 올리고 다시 해 보시죠.","TWN":"(TWN)방금 그 말씀, 가슴에 손을 올리고 다시 해 보시죠."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"크흠....\\n오늘 연락한 건 보고할 사항이 있어서겠지.","JPN":"クフム....\\n今日連絡したのは報告する事項があってだろう。","ENG":"(ENG)크흠....\\n오늘 연락한 건 보고할 사항이 있어서겠지.","TWN":"(TWN)크흠....\\n오늘 연락한 건 보고할 사항이 있어서겠지."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"새디어스 모건에 대한 추가 정보를 입수했습니다.","JPN":"タデウス・モーガンに対する追加情報を手に入れました。","ENG":"(ENG)새디어스 모건에 대한 추가 정보를 입수했습니다.","TWN":"(TWN)새디어스 모건에 대한 추가 정보를 입수했습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"신분 정화 작업 책임자와 관련된 내용인가?","JPN":"身分浄化作業責任者と関連する内容であるか?","ENG":"(ENG)신분 정화 작업 책임자와 관련된 내용인가?","TWN":"(TWN)신분 정화 작업 책임자와 관련된 내용인가?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"연관성이 있다고 판단했습니다.","JPN":"関連性があると判断しました。","ENG":"(ENG)연관성이 있다고 판단했습니다.","TWN":"(TWN)연관성이 있다고 판단했습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"좋아. 말해 보게.","JPN":"良い。言ってみなさい。","ENG":"(ENG)좋아. 말해 보게.","TWN":"(TWN)좋아. 말해 보게."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"책임자의 사체가 발견된 직후, 왕립교정국이 관리하는 C급 교도소에 신규 수용자가 들어왔습니다. ","JPN":"責任者の死体が発見された直後、王立校正国が管理するC級刑務所に新規収容者が入って来ました。","ENG":"(ENG)책임자의 사체가 발견된 직후, 왕립교정국이 관리하는 C급 교도소에 신규 수용자가 들어왔습니다. ","TWN":"(TWN)책임자의 사체가 발견된 직후, 왕립교정국이 관리하는 C급 교도소에 신규 수용자가 들어왔습니다. "},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"성명은 루크 샌더스, 당시 50대 남성으로 폭행죄 때문에 수감되었습니다.","JPN":"声明はルークサンダース、当時５０代男性で暴行罪のために収監されました。","ENG":"(ENG)성명은 루크 샌더스, 당시 50대 남성으로 폭행죄 때문에 수감되었습니다.","TWN":"(TWN)성명은 루크 샌더스, 당시 50대 남성으로 폭행죄 때문에 수감되었습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그 샌더스 씨란 사람, 실존하는 인물인가?","JPN":"そのサンダースさんとは人、実存する人物であるか?","ENG":"(ENG)그 샌더스 씨란 사람, 실존하는 인물인가?","TWN":"(TWN)그 샌더스 씨란 사람, 실존하는 인물인가?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"루크 샌더스는 스코틀랜드 태생으로, 고향에서 식료품점을 운영하고 있었습니다.","JPN":"ルークサンダースはスコットランド生まれで、故郷で食料品店を運営していました。","ENG":"(ENG)루크 샌더스는 스코틀랜드 태생으로, 고향에서 식료품점을 운영하고 있었습니다.","TWN":"(TWN)루크 샌더스는 스코틀랜드 태생으로, 고향에서 식료품점을 운영하고 있었습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"주민들에 따르면 자동차 여행이 취미여서 이따금 며칠씩 가게 문을 닫고 어디로 훌쩍 떠났다는군요.","JPN":"住民によれば自動車旅行が趣味のため時折何日ずつ店門を閉じてどこにふらりと発ったと言うのよです。","ENG":"(ENG)주민들에 따르면 자동차 여행이 취미여서 이따금 며칠씩 가게 문을 닫고 어디로 훌쩍 떠났다는군요.","TWN":"(TWN)주민들에 따르면 자동차 여행이 취미여서 이따금 며칠씩 가게 문을 닫고 어디로 훌쩍 떠났다는군요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"교도소에 수용될 당시에도 여행지에서 시비가 붙었다고 증언했습니다.","JPN":"刑務所に収容される当時にも旅先で是非が付いたと証言しました。","ENG":"(ENG)교도소에 수용될 당시에도 여행지에서 시비가 붙었다고 증언했습니다.","TWN":"(TWN)교도소에 수용될 당시에도 여행지에서 시비가 붙었다고 증언했습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그렇게만 들어서는 그림이 한눈에 들어오질 않는군.","JPN":"そのようにだけ入っては絵がわき目に入って来るのをないね。","ENG":"(ENG)그렇게만 들어서는 그림이 한눈에 들어오질 않는군.","TWN":"(TWN)그렇게만 들어서는 그림이 한눈에 들어오질 않는군."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"루크 샌더스는 새디어스 모건의 주소지 옆집에 살고 있었습니다.","JPN":"ルークサンダースはタデウス・モーガンの住所の場所隣家に住んでいました。","ENG":"(ENG)루크 샌더스는 새디어스 모건의 주소지 옆집에 살고 있었습니다.","TWN":"(TWN)루크 샌더스는 새디어스 모건의 주소지 옆집에 살고 있었습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그리고 사건 발생 3년 전에 지병인 심근경색으로 사망하여 주민들이 매장했다고 합니다.","JPN":"そして事件発生3年前に持病である心筋梗塞で死亡して住民が埋葬したと言います。","ENG":"(ENG)그리고 사건 발생 3년 전에 지병인 심근경색으로 사망하여 주민들이 매장했다고 합니다.","TWN":"(TWN)그리고 사건 발생 3년 전에 지병인 심근경색으로 사망하여 주민들이 매장했다고 합니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"사망신고는 어떻게 됐나?","JPN":"死亡届けはどうなったか?","ENG":"(ENG)사망신고는 어떻게 됐나?","TWN":"(TWN)사망신고는 어떻게 됐나?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"누군가 중간에서 손을 써 뒀더군요.\\n담당의는 사망 진단을 내렸지만 행정적으로는 처리되지 않았습니다.","JPN":"誰か中間で手を回しておきましたよ。\\n談唐依は死亡診断を下したが行政的には処理されなかったです。","ENG":"(ENG)누군가 중간에서 손을 써 뒀더군요.\\n담당의는 사망 진단을 내렸지만 행정적으로는 처리되지 않았습니다.","TWN":"(TWN)누군가 중간에서 손을 써 뒀더군요.\\n담당의는 사망 진단을 내렸지만 행정적으로는 처리되지 않았습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"누군가가 교도소에 머무는 동안엔 생존한 것으로 파악됐단 뜻이죠.","JPN":"誰かが刑務所に留まる間には生存したことで把握されたという意味ですよ。","ENG":"(ENG)누군가가 교도소에 머무는 동안엔 생존한 것으로 파악됐단 뜻이죠.","TWN":"(TWN)누군가가 교도소에 머무는 동안엔 생존한 것으로 파악됐단 뜻이죠."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"간혹 있는 케이스긴 하지. 보통 범인을 찾는다고 하면 교도소에 들어가 있을 경우는 간과하니까.","JPN":"たまにあるケースだとする。普通犯人を探すとすれば刑務所に入っている場合は見逃すから。","ENG":"(ENG)간혹 있는 케이스긴 하지. 보통 범인을 찾는다고 하면 교도소에 들어가 있을 경우는 간과하니까.","TWN":"(TWN)간혹 있는 케이스긴 하지. 보통 범인을 찾는다고 하면 교도소에 들어가 있을 경우는 간과하니까."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"가벼운 경범죄를 저질러서 고의로 감옥에 들어가 버리면 당장 수사망에선 벗어날 수 있으니 말일세.","JPN":"軽い軽犯罪を犯して故意で監獄に入ってしまえばすぐ捜査網では脱することができるから言葉だよ。","ENG":"(ENG)가벼운 경범죄를 저질러서 고의로 감옥에 들어가 버리면 당장 수사망에선 벗어날 수 있으니 말일세.","TWN":"(TWN)가벼운 경범죄를 저질러서 고의로 감옥에 들어가 버리면 당장 수사망에선 벗어날 수 있으니 말일세."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"네. 그 말씀대로 루크 샌더스는 짧은 수감 생활을 마치고 석방된 뒤 종적을 감췄습니다.","JPN":"はい。そのお話どおりルークサンダースは短い収監生活を終えて釈放された後足跡を隠しました。","ENG":"(ENG)네. 그 말씀대로 루크 샌더스는 짧은 수감 생활을 마치고 석방된 뒤 종적을 감췄습니다.","TWN":"(TWN)네. 그 말씀대로 루크 샌더스는 짧은 수감 생활을 마치고 석방된 뒤 종적을 감췄습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그러니까 자네 얘기를 정리해 보면 이렇군.","JPN":"そうするから君の話を整理してみればこのようであるね。","ENG":"(ENG)그러니까 자네 얘기를 정리해 보면 이렇군.","TWN":"(TWN)그러니까 자네 얘기를 정리해 보면 이렇군."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"새디어스 모건이 신분 정화 작업 책임자를 자살로 위장하여 살해했다.","JPN":"タデウス・モーガンが身分浄化作業責任者を自殺で偽装して殺害した。","ENG":"(ENG)새디어스 모건이 신분 정화 작업 책임자를 자살로 위장하여 살해했다.","TWN":"(TWN)새디어스 모건이 신분 정화 작업 책임자를 자살로 위장하여 살해했다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그 이후 만약의 경우를 대비하기 위해 거짓 신분을 사용해서 교도소에 수감되어 있었다.","JPN":"その以後もしの場合を備えるために偽り身分を使って刑務所に収監されていた。","ENG":"(ENG)그 이후 만약의 경우를 대비하기 위해 거짓 신분을 사용해서 교도소에 수감되어 있었다.","TWN":"(TWN)그 이후 만약의 경우를 대비하기 위해 거짓 신분을 사용해서 교도소에 수감되어 있었다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"범행 동기도 추측할 수 있게 되었습니다.","JPN":"犯行動機も推測することができるようになりました。","ENG":"(ENG)범행 동기도 추측할 수 있게 되었습니다.","TWN":"(TWN)범행 동기도 추측할 수 있게 되었습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"책임자는 당시 자영업 실패로 빚 독촉에 시달리던 상황이었다고 합니다.","JPN":"責任者は当時自営業失敗で借金督促に苦しんだ状況だったとします。","ENG":"(ENG)책임자는 당시 자영업 실패로 빚 독촉에 시달리던 상황이었다고 합니다.","TWN":"(TWN)책임자는 당시 자영업 실패로 빚 독촉에 시달리던 상황이었다고 합니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"이때 그에게 과거 신분 정화 작업 대상자들의 정보를 넘기라는 제안이 들어왔던 모양입니다.","JPN":"この時彼に過去身分浄化作業対象者の情報を越すという提案が入って来たようです。","ENG":"(ENG)이때 그에게 과거 신분 정화 작업 대상자들의 정보를 넘기라는 제안이 들어왔던 모양입니다.","TWN":"(TWN)이때 그에게 과거 신분 정화 작업 대상자들의 정보를 넘기라는 제안이 들어왔던 모양입니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"하지만 넘기지 못했겠지.\\n그전에 죽었을 테니까.","JPN":"しかし越すことができなかったでしょう。\\n以前に死んだはずだから。","ENG":"(ENG)하지만 넘기지 못했겠지.\\n그전에 죽었을 테니까.","TWN":"(TWN)하지만 넘기지 못했겠지.\\n그전에 죽었을 테니까."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"네. 현장에서 활동 중인 자신이야 대처가 쉽겠지만, 다른 이들은 아무것도 모르고 뜬눈으로 당했겠죠.","JPN":"はい。現場で活動中の自分なら対処が容易だが、他のこれらは何も知らなくて開けた目であいます。","ENG":"(ENG)네. 현장에서 활동 중인 자신이야 대처가 쉽겠지만, 다른 이들은 아무것도 모르고 뜬눈으로 당했겠죠.","TWN":"(TWN)네. 현장에서 활동 중인 자신이야 대처가 쉽겠지만, 다른 이들은 아무것도 모르고 뜬눈으로 당했겠죠."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"다른 전향자들 안전까지 걱정했다.... 이 바닥에선 좀 낭만적인 해석 같은데.","JPN":"別の転向者安全まで心配した....この床ではちょっとロマンチックな解析のようであるが。","ENG":"(ENG)다른 전향자들 안전까지 걱정했다.... 이 바닥에선 좀 낭만적인 해석 같은데.","TWN":"(TWN)다른 전향자들 안전까지 걱정했다.... 이 바닥에선 좀 낭만적인 해석 같은데."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"책임자에게 거래를 제안했다던 조직을 추적 중입니다.\\n새로운 결과가 나오는 대로 전달드리겠습니다.","JPN":"責任者に取引をジェアンヘッダドン組織を追跡中です。\\n新しい結果が出次第伝達させていただきます。","ENG":"(ENG)책임자에게 거래를 제안했다던 조직을 추적 중입니다.\\n새로운 결과가 나오는 대로 전달드리겠습니다.","TWN":"(TWN)책임자에게 거래를 제안했다던 조직을 추적 중입니다.\\n새로운 결과가 나오는 대로 전달드리겠습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};